//            (P20190728645_KFL190163)








/////////////////////////GreenBank-실명증표 스캐닝-Start////////////////////////

// 실명증표 축약 이미지Key 보관을 위한 전역 변수 선언
scwin.strImageKey1 = "";
scwin.strImageKey2 = "";
scwin.strImageKey3 = "";
scwin.strImageKey4 = "";
scwin.strImageKey5 = "";
scwin.strImageKey6 = "";
scwin.strImageKey7 = "";
scwin.strImageKey8 = "";

// 고객실명번호 보관을 위한 전역 변수 선언
scwin.strCuniqno = "";


// 실명증표 인자문구를 보관하기 위한 전역변수 선언
scwin.strScanTyping = "";

scwin.onpageload = function() {
	scwin.OnInitScreen();
};

scwin.onpageunload = function() {};

/////////////////////////GreenBank-실명증표 스캐닝-End//////////////////////////


scwin.OnInitScreen = function() {
    //여기에 구현코드를 삽입하세요.
    /*	공통버튼용*/

    ///////////////////////GreenBank-실명증표 스캐닝-Start////////////////////////
    // 실명증표 스캔 버튼의 Visible 설정값 정의 - 스캔 대상 거래화면일 경우
    //////////////////////////////////////////////////////////////////////////////

    // 실명증표 스캔버튼 숨기기 설정
    $c.iz.data.commonButtonVisible(7, false);

    // 해당 지점의 그린뱅크 오픈 여부 확인
    // Return : TRUE(오픈 대상 지점), FALSE(오픈 미대상 지점)
    if ($c.com.critical.checkGreenBankOpen()) {
        //대상 지점인 경우 실명증표 스캔 버튼이 보이도록 속성 변경
        $c.iz.data.commonButtonVisible(7, true);
        // 스캔화면 자동호출대상인 경우 실명증표 스캔 버튼 클릭 이벤트 호출
        //OnSendKey8();
    }
    ///////////////////////GreenBank-실명증표 스캐닝-End//////////////////////////

    //////////////// [디지털서식] 디지털 버튼 삽입로직-Start /////////////////////2017.08.21
    $c.com.critical.cmdDigitalForm("DF_INIT", "");
    //////////////// [디지털서식] 디지털 버튼 삽입로직-End  //////////////////////	
};



