scwin.RqstrCnoDstcd_OnItemChanged = function(e) {
    //여기에 구현코드를 삽입하세요.
    if (RqstrCno.getValue() != "") {
        return;
    } else {
        if (RqstrCnoDstcd.getValue() == "1" || RqstrCnoDstcd.getValue() == "6") {
            RqstrCno.setEditFormat("AAAAAA-AAAAAAA");
        } else if (RqstrCnoDstcd.getValue() == "2") {
            RqstrCno.setEditFormat("AAA-AA-AAAAA");
        } else if (RqstrCnoDstcd.getValue() == "3") {
            RqstrCno.setEditFormat("AAAAAA-AAAAAAA");
        } else {
            RqstrCno.setEditFormat("AAAAAAAAAAAAA");
        }
    }
};


//-----------------------------------------------------------
// 검색구분(고객번호,고객정보번호) 변경에 따른 이벤트
//-----------------------------------------------------------
scwin.serchNoDstic_OnItemChanged = function(e) {
    if (RqstrAcno.getValue() == "") {
        //고객번호 선택
        if (serchNoDstic.getValue() == "1") {
            //발행인고객구분코드, 발행인고객번호 활성화
            RqstrCnoDstcd.clear();
            RqstrCnoDstcd.show('');
            RqstrCnoDstcd.setMandatory(true);
            RqstrCno.setValue();
            RqstrCno.show('');
            RqstrCno.setMandatory(true);


            //고객정보번호 비활성화
            CustIdnfr.setValue();
            CustIdnfr.hide();
            CustIdnfr.setMandatory(false);
            CustMgtNo.setValue();
            CustMgtNo.hide();
            CustMgtNo.setMandatory(false);

            //Button4 위치조정
            Button4.setPosition(395, serchNoDstic.Y);
        }
        //고객정보번호 선택
        else {
            //발행인고객구분코드, 발행인고객번호 비활성화
            RqstrCnoDstcd.clear();
            RqstrCnoDstcd.hide();
            RqstrCnoDstcd.setMandatory(false);
            RqstrCno.setValue();
            RqstrCno.hide();
            RqstrCno.setMandatory(false);

            //고객정보번호 활성화,위치조정
            CustIdnfr.setValue();
            CustIdnfr.show('');
            CustIdnfr.setMandatory(true);
            CustMgtNo.setValue();
            CustMgtNo.show('');
            CustMgtNo.setMandatory(true);
            CustIdnfr.setPosition(250, serchNoDstic.Y);
            CustMgtNo.setPosition(338, serchNoDstic.Y);

            //Button4 위치조정
            Button4.setPosition(388, serchNoDstic.Y);
        }
    } else {
        serchNoDstic.getValue() == "1";
        RqstrCnoDstcd.setMandatory(false);
        RqstrCno.setMandatory(false);
        CustIdnfr.setMandatory(false);
        CustMgtNo.setMandatory(false);
    }
};



scwin.Button2_OnClick = function(e) {
    //Get data:  고객번호(cuniqno), 고객명(custnm)
    //	고객명조회	KAA04900001
    Link.scopDstic = "B";
    if (serchNoDstic.getValue() == "1") {
        Link.cuniqno = RqstrCno.getValue();
        Link.custnm = rqstrCustnm.getValue(); //고객명 입력해도 전체 조회됨, =무의미  
    } else {
        Link.custIdnfr = CustIdnfr.getValue();
        Link.custMgtNo = CustMgtNo.getValue();
    }
    $c.iz.screen.popup("KAA04900001", "DATALINK");
    //	RqstrCno.Data = Link.cuniqno;
    //	rqstrCustnm.Data        = Link.custnm;   // 18.08.24


    var custIdnfrStr = Link.custIdnfr;
    var custMgtNoStr = Link.custMgtNo;
    var custnmStr = Link.custnm;

    //고객정보가 존재하지 않거나, 고객명조회 팝업창에서 고객명을 선택하지 않고
    //화면을 닫기버튼 또는 X 버튼으로 화면을 닫은 경우 
    if ("undefined" == typeof(custIdnfrStr) || "" == custIdnfrStr) {
        autoInquryCustnm.setValue();
        autoInquryCustnm.hide();
        rqstrCustnm.show('');
        rqstrCustnm.setPosition(168, Text_rqstrCustnm.Y);
        Desc4.show('');
        scwin.custIdnfrFee = '0000000000'; // 수수료조회를 위한 KBPIN 조립
    } else if ("" == custnmStr) {
        // 잠재고객 등의 사유로 고객명 없는 경우 --> 고객명 직접 입력
        autoInquryCustnm.setValue();
        autoInquryCustnm.hide();
        rqstrCustnm.show('');
        rqstrCustnm.setPosition(168, Text_rqstrCustnm.Y);
        Desc4.show('');
        scwin.custIdnfrFee = custIdnfrStr; // 수수료조회를 위한 KBPIN 조립
    } else {
        autoInquryCustnm.show('');
        autoInquryCustnm.setValue(custnmStr);
        rqstrCustnm.hide();
        rqstrCustnm.setValue();
        Desc4.hide();
        scwin.custIdnfrFee = custIdnfrStr; // 수수료조회를 위한 KBPIN 조립
    }
    $c.iz.data.clearLinkData();
};


scwin.Button4_OnClick = function(e) {
    //여기에 구현코드를 삽입하세요.
    //고객주의 의무등록조회(KAA04740001)	
    //고객번호 선택
    if (serchNoDstic.getValue() == "1") {
        Link.cno = RqstrCno.getValue();
    } else {
        //고객정보번호 선택
        Link.CustIdnfr = CustIdnfr.getValue();
    }
    $c.iz.screen.popup("KAA04740001", "DATALINK");
};



scwin.cbill1_OnItemChanged = function(e) {
    scwin.SetFeeDstcd(); // 수수료징수구분코드 설정

    ////권종은 10, 30, 50, 100, 99 이외는 권종오류 message처리
    if (cbill1.getValue() == "010") {
        nost1.setValue();
        chekStartNo1.setValue();
        chekEndNo1.setValue();
        unitAmt1.setValue();
        nost1.setDisabled(false);
        chekStartNo1.setMandatory(false);
        unitAmt1.setDisabled(true);
        unitAmt1.setValue(100000);
        unitTotAmt1.setValue(0);
    } else if (cbill1.getValue() == "030") {
        nost1.setValue();
        chekStartNo1.setValue();
        chekEndNo1.setValue();
        unitAmt1.setValue();
        nost1.setDisabled(false);
        chekStartNo1.setMandatory(false);
        unitAmt1.setDisabled(true);
        unitAmt1.setValue(300000);
        unitTotAmt1.setValue(0);
    } else if (cbill1.getValue() == "050") {
        nost1.setValue();
        chekStartNo1.setValue();
        chekEndNo1.setValue();
        unitAmt1.setValue();
        nost1.setDisabled(false);
        chekStartNo1.setMandatory(false);
        unitAmt1.setDisabled(true);
        unitAmt1.setValue(500000);
        unitTotAmt1.setValue(0);
    } else if (cbill1.getValue() == "100") {
        nost1.setValue();
        chekStartNo1.setValue();
        chekEndNo1.setValue();
        unitAmt1.setValue();
        nost1.setDisabled(false);
        chekStartNo1.setMandatory(false);
        unitAmt1.setDisabled(true);
        unitAmt1.setValue(1000000);
        unitTotAmt1.setValue(0);
    } else if (cbill1.getValue() == "099") {
        nost1.setValue();
        chekStartNo1.setValue();
        chekEndNo1.setValue();
        unitAmt1.setValue();
        nost1.setDisabled(false);
        unitAmt1.setDisabled(false);
        chekStartNo1.setMandatory(true);
        unitAmt1.setMandatory(true);
        unitAmt1.setValue(0);
        unitTotAmt1.setValue(0);
    } else if (cbill1.getValue() == "") {
        nost1.setValue();
        chekStartNo1.setValue();
        chekEndNo1.setValue();
        chekStartNo1.setMandatory(false);
        unitAmt1.setMandatory(false);
        unitAmt1.setValue(0);
        unitTotAmt1.setValue(0);
    }
};


/*  수표예정번호 등록으로 수표시작번호 미입력할수 있음 */


