scwin.cbill4_OnItemChanged = function(e) {
    scwin.SetFeeDstcd(); // 수수료징수구분코드 설정

    ////권종은 10, 30, 50, 100, 99 이외는 권종오류 message처리
    if (cbill4.getValue() == "") {
        nost4.setValue();
        chekStartNo4.setValue();
