scwin.fillChar = function(Character, Len, Value) {
    if (Value == "") {
        return;
    }
    var strReturnValue = Value;
    if (Len > Value.length) {
        for (var i = Value.length; i < Len; i++) {
            strReturnValue = Character + strReturnValue;
        }
    }
    return strReturnValue;
};


scwin.SettotalIssuAmt = function() {
    var strnost1Amt = 0;
    var strnost2Amt = 0;
    var strnost3Amt = 0;
    var strnost4Amt = 0;
    var strnost5Amt = 0;
    totalIssuAmt.setValue(0);
    if (nost1.getValue() != 0 && nost1.getValue() != "" && unitAmt1.getValue() != 0 && unitAmt1.getValue() != "") {
        strnost1Amt = parseInt(nost1.getValue()) * parseInt(unitAmt1.getValue());
    }
    if (nost2.getValue() != 0 && nost2.getValue() != "" && unitAmt2.getValue() != 0 && unitAmt2.getValue() != "") {
        strnost2Amt = parseInt(nost2.getValue()) * parseInt(unitAmt2.getValue());
    }
    if (nost3.getValue() != 0 && nost3.getValue() != "" && unitAmt3.getValue() != 0 && unitAmt3.getValue() != "") {
        strnost3Amt = parseInt(nost3.getValue()) * parseInt(unitAmt3.getValue());
    }
    if (nost4.getValue() != 0 && nost4.getValue() != "" && unitAmt4.getValue() != 0 && unitAmt4.getValue() != "") {
        strnost4Amt = parseInt(nost4.getValue()) * parseInt(unitAmt4.getValue());
    }
    if (nost5.getValue() != 0 && nost5.getValue() != "" && unitAmt5.getValue() != 0 && unitAmt5.getValue() != "") {
        strnost5Amt = parseInt(nost5.getValue()) * parseInt(unitAmt5.getValue());
    }
    totalIssuAmt.setValue(strnost1Amt + strnost2Amt + strnost3Amt + strnost4Amt + strnost5Amt);
};

