scwin.cnclDstic_OnItemChanged = function(e) {
    //* 콤보내용 :  9 취소, 8 정정, 7 정정취소
    //* 9 취소 선택시
    //  수표발행정보 그룹박스 활성화 그외 항목은 비활성화
    //  '거래취소정정사유구분' 항목 활성화
    //* 8 정정 및 7 정정취소 선택시
    //  수표발행정보 그룹박스 활성화 그외 항목은 비활성화
    //  '기산일',  '거래취소정정사유구분'  항목 활성화
    //주의 : 취소정정구분 콤보박스 아무런 값도 선택되지 않은경우는 정상거래이므로 기존 이벤트 적용되어야함
    //
    //** 공통정보 조립 **
    //- 취소구분코드에  9 취소, 8 정정, 7 정정취소 null 인 경우 0
    //- 취소유형구분코드 = '7', 취소사유내용,   트랜코드  공통부에 조립요청 

    scwin.SetProxyMandatory(); // 대리인필수지정
    scwin.SetFeeDstcd(); // 수수료징수구분코드 설정

    GroupBox4.setDisabled(false);
    cshTrferDstcd.setDisabled(false);
    cshTrfamt.setDisabled(false);
    RqstrAcno.setDisabled(false);
    RqstrCnoDstcd.setDisabled(false);
    RqstrCno.setDisabled(false);
    rqstrCustnm.setDisabled(false);
    GroupBox5.setDisabled(false);
    PanelKYC.setDisabled(false);
    PanelKYC.show('');
    if (cnclDstic.getValue() == "9") {
        CnclResnDstic.setDisabled(false);
        GroupBox4.setValue("");
        cshTrferDstcd.setDisabled(true);
        cshTrferDstcd.setMandatory(false); //18.08.24
        cshTrfamt.setDisabled(true);
        RqstrAcno.setDisabled(false);
        RqstrCnoDstcd.setDisabled(false);
        RqstrCno.setDisabled(false);
        rqstrCustnm.setDisabled(false);
    } else if (cnclDstic.getValue() == "8" || cnclDstic.getValue() == "7") {
        GroupBox4.setValue("");
        CnclResnDstic.setDisabled(false);
        cshTrferDstcd.setDisabled(true);
        cshTrferDstcd.setMandatory(false); //18.08.24
        cshTrfamt.setDisabled(true);
        RqstrAcno.setDisabled(false);
        RqstrCnoDstcd.setDisabled(false);
        RqstrCno.setDisabled(false);
        rqstrCustnm.setDisabled(false);
        PanelKYC.hide();
        PanelKYC.setDisabled(true);
        $c.iz.data.messageSlide("※금일 중요증서잔고 변동유의※ \n\n " + "수표발행 정정거래후 정당한 수표발행분에 대한 거래는" + " 반드시 [기산일자]를 입력해야 수표중요증서 재고수량에 변동이 없습니다.");
    } else if (cnclDstic.getValue() == "0") {
        GroupBox4.setDisabled(false);
        cshTrferDstcd.setDisabled(false);
        cshTrferDstcd.setMandatory(true); //18.08.24
        cshTrfamt.setDisabled(false);
        RqstrAcno.setDisabled(false);
        RqstrCnoDstcd.setDisabled(false);
        RqstrCno.setDisabled(false);
        rqstrCustnm.setDisabled(false);
        GroupBox5.setDisabled(false);
        PanelKYC.setDisabled(false);
        PanelKYC.show('');
        CnclResnDstic.setValue("00");
    }
};

