scwin.OnSendKey = function() {
    //고객정보번호(고객식별자+관리번호) 체크
    if (serchNoDstic.getValue() == "2") {
        var tmpCustIdnfr1 = CustIdnfr.getValue();
        if (tmpCustIdnfr1.substr(9, 1) == "") {
            $c.iz.data.messageSlide("고객식별자 10자리를 \n정확하게 입력하십시요.");
            CustIdnfr.focus();
            return;
        }
        if (CustMgtNo.getValue() == "") {
            $c.iz.data.messageSlide("고객관리번호를 \n입력하여 주십시요.");
            CustMgtNo.focus();
            return;
        }
        //고객관리번호 채우기
        CustMgtNo.setValue(scwin.fillChar("0", 5, CustMgtNo.getValue()));
    }
    if (RqstrAcno.getValue() == "") {
        if (serchNoDstic.getValue() == "1") {
            if ((RqstrCnoDstcd.getValue() == "") || (RqstrCno.getValue() == "")) {
                $c.iz.data.messageSlide("발행인계좌번호 또는 발행인고객번호를 입력해야합니다.");
                return;
            }
        } else {
            if ((CustIdnfr.getValue() == "") || (CustMgtNo.getValue() == "")) {
                $c.iz.data.messageSlide("발행인계좌번호 또는 발행인고객정보번호를 입력해야합니다.");
                return;
            }
        }
    } else {
        var CnoBank = "";
        CnoBank = RqstrCno.getValue();
        if (CnoBank.substr(2, 4) == "BANK") {
            if (serchNoDstic.getValue() == "1") {
                if ((RqstrCnoDstcd.getValue() == "") || (RqstrCno.getValue() == "")) {
                    $c.iz.data.messageSlide("발행인고객번호를 입력해야합니다.");
                    return;
                }
            } else {
                $c.iz.data.messageSlide("발행인고객번호를 입력해야합니다.");
                return;
            }
        } else {
            if (((RqstrCnoDstcd.getValue() != "") || (RqstrCno.getValue() != "")) ||
                ((CustIdnfr.getValue() != "") || (CustMgtNo.getValue() != ""))) {
                $c.iz.data.messageSlide("발행인계좌번호 또는 발행인고객번호 중 한가지 항목만 선택 입력합니다.");
                return;
            }
        }
    }

    //180907  T1BANKxxx, T2BANKxxx 일경우 계좌번호 필수입력 및 일반권거래인지 검증 
    if ("" != RqstrCno.getValue()) {
        var bankStr = RqstrCno.getValue().substr(2, 4).toUpperCase();
        if ("BANK" == bankStr) {
            if ("" == RqstrAcno.getValue()) {
                $c.iz.data.messageSlide("발행인계좌번호를 입력해야합니다.");
                return;
            }
            if ("099" == cbill1.getValue() ||
                "099" == cbill2.getValue() ||
                "099" == cbill3.getValue() ||
                "099" == cbill4.getValue() ||
                "099" == cbill5.getValue()) {
                $c.iz.data.messageSlide("일반권은 TxBANKxxx를 발행인고객번호로 입력할 수 없습니다");
                return;
            }
        }
    }
    if (cnclDstic.getValue() == "" || cnclDstic.getValue() == "0") {
        if (cshTrferDstcd.getValue() == "") {
            $c.iz.data.messageSlide("현금대체구분코드는 필수입력항목입니다");
            return;
        }
    }
    if (CnclResnDstic.getValue() == "99" && CnclResnCtnt.getValue() == "") {
        $c.iz.data.messageSlide("기타오류에 해당하는 사유내용을 입력하세요.");
        return;
    }
    /*	  if ((RqstrAcno.Value ==  "") &&
    	      (RqstrCno.Value  ==  ""))
        	{
    	      MessageSlide("발행의뢰인계좌번호 또는 발행의뢰인고객번호중 한가지 항목는 선택 입력해야합니다  ");
    	      return;
            }
          else
    */
    if (cnclDstic.getValue() != "0") {
        //var CancelCode = CnclResnCtnt.Data                //취소사유코드
        var CancelCode = CnclResnDstic.getValue(); //취소사유코드 - 2013.06.26 오류정정함

        //취소사유내용
        var CancelDesc;
        if (CnclResnDstic.getValue() == "99") {
            CancelDesc = CnclResnCtnt.getValue();
        } else {
            CancelDesc = CnclResnDstic.GetComboValue;
        }
    }
    if (cnclDstic.getValue() == "9") {
        $c.iz.tran.setTranID("KFL0101110");
        if ($c.iz.data.setChildData("SetTranHeader()", "PanelKYC") == false) return false;

        ///////////////////////GreenBank-실명증표 스캐닝-Start////////////////////////////////////
        // 실명증표스캔 이미지전송후, 넘겨받은 이미지키를 등록거래시 업무공통부에 설정
        // SetImageKeyInTranHeader() 공통함수는 등록거래에 사용하는 거래코드의 SetTranID 밑에 작성
        //////////////////////////////////////////////////////////////////////////////////////////

        // 업무공통부에 PPR 실명증표 이미지키 설정
        $c.com.setImageKeyInTranHeader();
        $c.iz.tran.setCancelTran("9", "7", "0", "1", CancelCode, CancelDesc);
        $c.iz.tran.WaitSend();
    } else if (cnclDstic.getValue() == "8") {
        $c.iz.tran.setTranID("KFL0101110");
        $c.com.setImageKeyInTranHeader();
        $c.iz.tran.setCancelTran("8", "7", "0", "1", CancelCode, CancelDesc);
        $c.iz.tran.WaitSend();
    } else if (cnclDstic.getValue() == "7") {
        $c.iz.tran.setTranID("KFL0101110");
        $c.com.setImageKeyInTranHeader();
        $c.iz.tran.setCancelTran("7", "7", "0", "1", CancelCode, CancelDesc);
        $c.iz.tran.WaitSend();
    } else {
        // 일반권 고액(10억이상)발행인 경우 스캔안내 POPUP처리
        var IsPopupTarget = false;
        if (Number(unitAmt1.getValue()) >= 1000000000 && "099" == cbill1.getValue()) {
            IsPopupTarget = true;
        }
        if (Number(unitAmt2.getValue()) >= 1000000000 && "099" == cbill2.getValue()) {
            IsPopupTarget = true;
        }
        if (Number(unitAmt3.getValue()) >= 1000000000 && "099" == cbill3.getValue()) {
            IsPopupTarget = true;
        }
        if (Number(unitAmt4.getValue()) >= 1000000000 && "099" == cbill4.getValue()) {
            IsPopupTarget = true;
        }
        if (Number(unitAmt5.getValue()) >= 1000000000 && "099" == cbill5.getValue()) {
            IsPopupTarget = true;
        }
        if ("" != idtrek.getValue()) // 기산일거래시 고액(10억) 스캔관련 팝업제외

        {
            IsPopupTarget = false;
        }
        if (true == IsPopupTarget) {
            var bRsult = $c.iz.data.confirm("일반자기앞수표 발행(장당 10억원이상)시에는 반드시 수표 스캔을 완료하고\n" + "교부하시기 바라며, 금융사고예방을 위해 수표 교부 후 스캔은 금지됩니다.\n" + "   - 수표 이미지 스캔 등록 [06-13-301] : 대출스캐너 이용              \n" + "취소 선택시 수표발행거래가 실행되지 않습니다!!", "발행확인");
        }
        if (false == IsPopupTarget || true == bRsult) {
            $c.iz.tran.setTranID("KFL0101110");
            if ($c.iz.data.setChildData("SetTranHeader()", "PanelKYC") == false) return false;

            ///////////////////////GreenBank-실명증표 스캐닝-Start////////////////////////////////////
            // 실명증표스캔 이미지전송후, 넘겨받은 이미지키를 등록거래시 업무공통부에 설정
            // SetImageKeyInTranHeader() 공통함수는 등록거래에 사용하는 거래코드의 SetTranID 밑에 작성
            //////////////////////////////////////////////////////////////////////////////////////////

            // 업무공통부에 PPR 실명증표 이미지키 설정
            $c.com.setImageKeyInTranHeader();


            //////// [디지털서식] 실행거래 전 디지털서식 작성완료 확인-Start /////////////2017.08.21

            // 디지털서식 작성중인지 확인
            if ($c.com.critical.cmdDigitalForm("DF_ISCONNECT", "") == "1") {
                // 디지털서식 작성완료 여부 확인
                if ($c.com.critical.cmdDigitalForm("DF_VALIDATE", $c.iz._tran.tranId) != "1") {
                    var confirmRtn = $c.iz.data.confirm("디지털서식 작성이 완료되지 않았습니다.\n" + "   그래도 계속 실행하시겠습니까?\n" + "   ※확인을 누르시면 작성중인\n" + " 디지털서식은 저장되지 않습니다.", "디지털서식 작성 미완료 알림");
                    if (confirmRtn == true) {
                        // 확인을 누르면 디지털서식 연동해제 요청 후 기존거래 진행
                        $c.com.critical.cmdDigitalForm("DF_DISCONNECT", "");
                    } else {
                        return false;
                    }
                }
            }
            //////// [디지털서식] 실행거래 전 디지털서식 작성완료 확인-End   /////////////

            $c.iz.tran.WaitSend();
        }
    }
};



