//수수료구분코드 설정
scwin.SetFeeDstcd = function() {
    // 2016.12.12일 open예정으로 운영엔 이 시점까지는 임의면제로 운영시스템 일시반영
    // 2016.12.12일 open시에 본 테스트로직 제거필요 test
    // ******************************** TEST ********************************
    /*if ( 'd' == System.servicemode || 'D' == System.servicemode )
    {
    	InquiryFeeButton.Enabled     = true;
    }
    else
    {
    	InquiryFeeButton.Enabled     = false;
    	feeLevyDstcd.Value           = '1';		// 수수료구분코드(0:현금, 9:대체, 1:면제)
    	return ;
    }*/
    // **********************************************************************

    if ("" != idtrek.getValue()) // 기산일

    {
        feeLevyDstcd.setDisabled(true);
        feeLevyDstcd.setMandatory(false);
        feeLevyDstcd.setValue('1'); // 수수료구분코드(0:현금, 9:대체, 1:면제)
        issuFeeRceitpTypngYn.setDisabled(true);
        issuFeeRceitpTypngYn.setValue('0'); // 발행수수료인자여부
        InquiryFeeButton.setDisabled(true);
        return;
    }
    if ('0' != cnclDstic.getValue()) // 거래취소정정구분

    {
        feeLevyDstcd.setDisabled(true);
        feeLevyDstcd.setMandatory(false);
        feeLevyDstcd.setValue('1'); // 수수료구분코드(0:현금, 9:대체, 1:면제)
        issuFeeRceitpTypngYn.setDisabled(true);
        issuFeeRceitpTypngYn.setValue('0'); // 발행수수료인자여부
        InquiryFeeButton.setDisabled(true);
        return;
    }

    // 일반권 권종입력한 경우 수수료징수구분 활성화
    if ("099" == cbill1.getValue() || "099" == cbill2.getValue() || "099" == cbill3.getValue() || "099" == cbill4.getValue() || "099" == cbill5.getValue()) {
        feeLevyDstcd.setDisabled(false);
        feeLevyDstcd.setMandatory(true);
        feeLevyDstcd.clearData();
        issuFeeRceitpTypngYn.setDisabled(false);
        issuFeeRceitpTypngYn.setValue('1'); // 발행수수료인자여부
        InquiryFeeButton.setDisabled(false);
    } else {
        feeLevyDstcd.setDisabled(true);
        feeLevyDstcd.setMandatory(false);
        feeLevyDstcd.setValue('1'); // 수수료구분코드(0:현금, 9:대체, 1:면제)
        issuFeeRceitpTypngYn.setDisabled(true);
        issuFeeRceitpTypngYn.setValue('0'); // 발행수수료인자여부
        InquiryFeeButton.setDisabled(true);
    }
};

