scwin.RqstrAcno_OnValidate = function(info) {
    //발행인계좌번호 입력 시 고객계좌조회 처리  18.08.24


    //고객정보거래안내  KAA0499241 : 계좌번호로 KBPIN, 고객명 단순 참조 (거래TIME 고려)
    //검색번호구분	serchNoDstcd    2:계좌번호

    if ("" != RqstrAcno.getValue()) {
        $c.iz.tran.setTranID("KAA0499241");
        $c.iz.tran.setInFDData("KAA0499241", "serchNoDstcd", "2");
        $c.iz.tran.setInFDData("KAA0499241", "serchNo", RqstrAcno.getValue());
        //			Tran.ASend();	
        $c.iz.tran.WaitSend();
        if (false == $c.iz._tran.bError) {
            var custIdnfrStr = $c.iz.tran.getOutFDData("KAA0499241", "screen", "custIdnfr");
            var custMgtNoStr = $c.iz.tran.getOutFDData("KAA0499241", "screen", "custMgtNo");
            var custnmStr = $c.iz.tran.getOutFDData("KAA0499241", "screen", "custnm");
            if ("" == custIdnfrStr) {
                autoInquryCustnm.setValue();
                RqstrCnoDstcd.setDisabled(false); //발행인고객구분 활성화
                RqstrCno.setDisabled(false); //발행인고객번호 활성화		 	
                scwin.custIdnfrFee = '0000000000'; //수수료조회를 위한 KBPIN 조립
            } else {
                autoInquryCustnm.show('');
                autoInquryCustnm.setValue(custnmStr);
                rqstrCustnm.hide();
                rqstrCustnm.setValue();
                Desc4.hide();
                RqstrCnoDstcd.setDisabled(true); //발행인고객구분 비활성화
                RqstrCno.setDisabled(true); //발행인고객번호 비활성화
                RqstrCnoDstcd.clear();
                RqstrCno.setValue();
                Button2.setDisabled(true); //고객명조회버튼 비활성화
                scwin.custIdnfrFee = custIdnfrStr; //수수료조회를 위한 KBPIN 조립
            }
        } else {
            autoInquryCustnm.setValue();
            RqstrCnoDstcd.setDisabled(false); //발행인고객구분 활성화
            RqstrCno.setDisabled(false); //발행인고객번호 활성화		 			
            scwin.custIdnfrFee = '0000000000'; //수수료조회를 위한 KBPIN 조립
        }
    }
};

scwin.RqstrCno_OnValidate = function(info) {
    //발행인고객번호 입력 시 고객명조회 자동팝업 18.08.24
    var bankStr = RqstrCno.getValue().substr(2, 4);
    bankStr = bankStr.toUpperCase();
    if ("BANK" == bankStr) {
        autoInquryCustnm.show('');
        autoInquryCustnm.setValue();
        rqstrCustnm.hide();
        rqstrCustnm.setValue();
        Button2.setDisabled(true); //고객명조회버튼 비활성화
        Desc4.hide();
        return; //T1BANKxxx, T2BANKxxx return
    }
    if ("" != RqstrCno.getValue()) {
        scwin.Button2_OnClick();
    }
};
